import java.util.*;

public class Solution {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        String line = sc.nextLine().trim();
        line = line.substring(1, line.length() - 1);
        String[] parts = line.split(",");
        int[] resources = new int[parts.length];
        for (int i = 0; i < parts.length; i++) {
            resources[i] = Integer.parseInt(parts[i].trim());
        }

        System.out.println(countValidSelections(resources));
    }

    public static int countValidSelections(int[] resources) {
        int count = 0;
        int n = resources.length;


        for (int start = 0; start < n; start++) {
            if (resources[start] == 0) {

                if (simulate(resources.clone(), start, -1)) {
                    count++;
                }
                if (simulate(resources.clone(), start, 1)) {
                    count++;
                }
            }
        }

        return count;
    }

    private static boolean simulate(int[] resources, int pos, int dir) {
        int n = resources.length;

        while (pos >= 0 && pos < n) {
            if (resources[pos] == 0) {

                pos += dir;
            } else {

                resources[pos]--;
                dir = -dir;
                pos += dir;
            }
        }


        for (int val : resources) {
            if (val != 0) {
                return false;
            }
        }
        return true;
    }
}

