import java.util.Scanner;

class Solution {
    public boolean canJohnWin(int n) {
        return simulate(n, 10, true);
    }

    private boolean simulate(int remaining, int toExtract, boolean johnTurn) {
        if (remaining < toExtract) {
            return !johnTurn;
        }

        return simulate(remaining - toExtract, toExtract - 1, !johnTurn);
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        Solution solution = new Solution();
        boolean result = solution.canJohnWin(n);
        System.out.println(result);
        scanner.close();
    }
}

