    int findSmallestID(int startID, int divisor) {
        for (int id = startID; ; id++) {
            int product = 1;
            int temp = id;
            while (temp > 0) {
                product *= (temp % 10);
                temp /= 10;
            }
            if (product % divisor == 0) {
                return id;
            }
        }
    }
};

