import "fmt"

func digitProduct(n int) int {
    product := 1
    for n > 0 {
        product *= n % 10
        n /= 10
    }
    return product
}

func findSmallestID(startID int, divisor int) int {
    for id := startID; ; id++ {
        if digitProduct(id)%divisor == 0 {
            return id
        }
    }
}

