    result := findSmallestID(startID, divisor)
    fmt.Println(result)
}

import java.util.Scanner;

class Solution {
    public int findSmallestID(int startID, int divisor) {
        int current = startID;
        while (true) {
            int product = getDigitProduct(current);
            if (product % divisor == 0) {
                return current;
            }
            current++;
        }
    }

    private int getDigitProduct(int num) {
        int product = 1;
        while (num > 0) {
            product *= (num % 10);
            num /= 10;
        }
        return product;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int startID = scanner.nextInt();
        int divisor = scanner.nextInt();

        Solution solution = new Solution();
        int result = solution.findSmallestID(startID, divisor);
        System.out.println(result);

        scanner.close();
    }
}

using namespace std;

const int MOD = 1000000007;

class Solution {
public:
    int lengthAfterModifications(string c, int k) {
        vector<long long> freq(26, 0);

        for (char ch : c) {
            freq[ch - 'a']++;
        }

        for (int step = 0; step < k; step++) {
            vector<long long> newFreq(26, 0);

            for (int i = 0; i < 26; i++) {
                if (freq[i] == 0) continue;

                if (i == 12) {
                    newFreq[13] = (newFreq[13] + freq[i]) % MOD;
                    newFreq[14] = (newFreq[14] + freq[i]) % MOD;
                } else {
                    int next = (i + 1) % 26;
                    newFreq[next] = (newFreq[next] + freq[i]) % MOD;
                }
            }

            freq = newFreq;
        }

        long long result = 0;
        for (int i = 0; i < 26; i++) {
            result = (result + freq[i]) % MOD;
        }

        return result;
    }
};

int main() {
    string c;
    int k;
    cin >> c >> k;

    Solution sol;
    cout << sol.lengthAfterModifications(c, k) << endl;

    return 0;
}

