func getReflection(c byte) byte {
    return 'z' - (c - 'a')
}

func calculateReflectionScore(t string) int {
    n := len(t)
    marked := make([]bool, n)
    score := 0

    for i := 0; i < n; i++ {
        if marked[i] {
            continue
        }

        reflection := getReflection(t[i])

        for j := i - 1; j >= 0; j-- {
            if !marked[j] && t[j] == reflection {
                marked[i] = true
                marked[j] = true
                score += i - j
                break
            }
        }
    }

    return score
}

func main() {
    var t string
    fmt.Scan(&t)
    result := calculateReflectionScore(t)
    fmt.Println(result)
}

