func getMinimumValue(m int) int {
	if m == 1 {
		return 1
	}

	bits := 0
	temp := m
	for temp > 0 {
		bits++
		temp >>= 1
	}

	result := (1 << bits) - 1

	if result >= m {
		return result
	}

	return (1 << (bits + 1)) - 1
}

