public class Solution {
    public int countTriplets(int[] measurements) {
        int count = 0;
        for (int i = 0; i <= measurements.length - 3; i++) {
            int first = measurements[i];
            int second = measurements[i + 1];
            int third = measurements[i + 2];
            if ((first + third) * 2 == second) {
                count++;
            }
        }
        return count;
    }

