import java.util.*;

public class Main {
    static class Point {
        double x, y;
        Point(double x, double y) {
            this.x = x;
            this.y = y;
        }
        double dist(Point other) {
            return Math.sqrt((x - other.x) * (x - other.x) + (y - other.y) * (y - other.y));
        }
    }

    static class Segment {
        Point p1, p2;
        double length;
        Segment(double x1, double y1, double x2, double y2) {
            p1 = new Point(x1, y1);
            p2 = new Point(x2, y2);
            length = p1.dist(p2);
        }
    }

    static int N;
    static double S, T;
    static Segment[] segments;
    static double minTime = Double.MAX_VALUE;

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        N = sc.nextInt();
        S = sc.nextDouble();
        T = sc.nextDouble();

        segments = new Segment[N];
        for (int i = 0; i < N; i++) {
            double a = sc.nextDouble();
            double b = sc.nextDouble();
            double c = sc.nextDouble();
            double d = sc.nextDouble();
            segments[i] = new Segment(a, b, c, d);
        }

        boolean[] used = new boolean[N];
        solve(new Point(0, 0), used, 0.0);

        System.out.println(minTime);
    }

    static void solve(Point currentPos, boolean[] used, double currentTime) {
        boolean allUsed = true;
        for (int i = 0; i < N; i++) {
            if (!used[i]) {
                allUsed = false;
                break;
            }
        }

        if (allUsed) {
            minTime = Math.min(minTime, currentTime);
            return;
        }

        for (int i = 0; i < N; i++) {
            if (!used[i]) {
                used[i] = true;


                double moveTime1 = currentPos.dist(segments[i].p1) / S;
                double sketchTime = segments[i].length / T;
                solve(segments[i].p2, used, currentTime + moveTime1 + sketchTime);


                double moveTime2 = currentPos.dist(segments[i].p2) / S;
                solve(segments[i].p1, used, currentTime + moveTime2 + sketchTime);

                used[i] = false;
            }
        }
    }
}

