public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int K = sc.nextInt();
        String C = sc.next();


        List<int[]> segments = new ArrayList<>();
        int i = 0;
        while (i < N) {
            if (C.charAt(i) == 'Y') {
                int start = i;
                while (i < N && C.charAt(i) == 'Y') {
                    i++;
                }
                int end = i - 1;
                segments.add(new int[]{start, end});
            } else {
                i++;
            }
        }


        int[] prevSeg = segments.get(K-2);
        int[] currSeg = segments.get(K-1);

        int r_prev = prevSeg[1];
        int l_curr = currSeg[0];
        int r_curr = currSeg[1];

        StringBuilder result = new StringBuilder();


        for (int j = 0; j <= r_prev; j++) {
            result.append(C.charAt(j));
        }


        int segmentLength = r_curr - l_curr + 1;
        for (int j = 0; j < segmentLength; j++) {
            result.append('Y');
        }


        for (int j = r_prev + segmentLength + 1; j <= r_curr; j++) {
            result.append('X');
        }


        for (int j = r_curr + 1; j < N; j++) {
            result.append(C.charAt(j));
        }

        System.out.println(result.toString());
    }
