char flip(char c) {
    if (c >= 'a' && c <= 'z') {
        return c - 'a' + 'A';
    } else {
        return c - 'A' + 'a';
    }
}

char solve(const string& M, long long K, int depth) {
    if (depth == 0) {
        return M[K - 1];
    }

    long long len = (long long)M.length() << depth;
    long long half = len / 2;

    if (K <= half) {
        return solve(M, K, depth - 1);
    } else {
        char c = solve(M, K - half, depth - 1);
        return flip(c);
    }
}

int main() {
    string M;
    cin >> M;

    int Q;
    cin >> Q;

    vector<char> results;

    for (int i = 0; i < Q; i++) {
        long long K;
        cin >> K;

        int depth = 0;
        long long len = M.length();

        while (len < K) {
            len *= 2;
            depth++;
        }

        results.push_back(solve(M, K, depth));
    }

    for (int i = 0; i < Q; i++) {
        if (i > 0) cout << " ";
        cout << results[i];
    }
    cout << endl;

    return 0;
}

