                int x = Integer.parseInt(st.nextToken());
                int c = Integer.parseInt(st.nextToken());

                int originalColor = plots[x];
                if (originalColor != c) {
                    Queue<Integer> queue = new LinkedList<>();
                    boolean[] visited = new boolean[N + 1];

                    queue.offer(x);
                    visited[x] = true;

                    while (!queue.isEmpty()) {
                        int curr = queue.poll();
                        plots[curr] = c;

                        if (curr > 1 && !visited[curr - 1] && plots[curr - 1] == originalColor) {
                            visited[curr - 1] = true;
                            queue.offer(curr - 1);
                        }

                        if (curr < N && !visited[curr + 1] && plots[curr + 1] == originalColor) {
                            visited[curr + 1] = true;
                            queue.offer(curr + 1);
                        }
                    }
                }
            } else {
                int c = Integer.parseInt(st.nextToken());
                int count = 0;
                for (int i = 1; i <= N; i++) {
