def main():
    N, Q = map(int, input().split())


    plots = [0] + list(range(1, N + 1))

    for _ in range(Q):
        query = list(map(int, input().split()))

        if query[0] == 1:
            x, c = query[1], query[2]
            original_type = plots[x]

            if original_type != c:

                to_change = []
                visited = [False] * (N + 1)
                stack = [x]

                while stack:
                    pos = stack.pop()
                    if visited[pos]:
                        continue
                    visited[pos] = True
                    to_change.append(pos)


