public class Main {
    static List<List<Integer>> results = new ArrayList<>();
    static int P, Q;

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        P = sc.nextInt();
        Q = sc.nextInt();

        List<Integer> current = new ArrayList<>();
        backtrack(current, 1);

