        List<int[]> openCells = new ArrayList<>();

        for (int i = 0; i < M; i++) {
            String row = sc.next();
            for (int j = 0; j < N; j++) {
                grid[i][j] = row.charAt(j);
                if (grid[i][j] == '.') {
                    openCells.add(new int[]{i, j});
                }
            }
        }

        int maxCovered = 0;
        int numOpen = openCells.size();

        for (int i = 0; i < numOpen; i++) {
            for (int j = i + 1; j < numOpen; j++) {
                int[] router1 = openCells.get(i);
                int[] router2 = openCells.get(j);

                int covered = 0;
                for (int[] cell : openCells) {
                    int dist1 = Math.abs(cell[0] - router1[0]) + Math.abs(cell[1] - router1[1]);
                    int dist2 = Math.abs(cell[0] - router2[0]) + Math.abs(cell[1] - router2[1]);

                    if (dist1 <= R || dist2 <= R) {
                        covered++;
                    }
                }

                maxCovered = Math.max(maxCovered, covered);
            }
        }

        System.out.println(maxCovered);
    }
}

