long long maxXor = 0;

void generateCombinations(const vector<long long>& A, int n, int k, int start, long long currentXor, int chosen) {
    if (chosen == k) {
        maxXor = max(maxXor, currentXor);
        return;
    }

    if (start >= n) return;

    for (int i = start; i <= n - (k - chosen); i++) {
        generateCombinations(A, n, k, i + 1, currentXor ^ A[i], chosen + 1);
    }
}

