import java.util.*;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int M = sc.nextInt();
        String A = sc.next();
        String B = sc.next();

        int n = A.length();
        int m = B.length();


        int[][] dp = new int[n + 1][m + 1];


        for (int i = 0; i <= n; i++) {
            for (int j = 0; j <= m; j++) {
                dp[i][j] = Integer.MAX_VALUE;
            }
        }

        dp[0][0] = 0;

        for (int i = 0; i <= n; i++) {
            for (int j = 0; j <= m; j++) {
                if (dp[i][j] > M) continue;


                if (i < n) {
                    dp[i + 1][j] = Math.min(dp[i + 1][j], dp[i][j] + 1);
                }


                if (j < m) {
                    dp[i][j + 1] = Math.min(dp[i][j + 1], dp[i][j] + 1);
                }


                if (i < n && j < m) {
                    if (A.charAt(i) == B.charAt(j)) {
                        dp[i + 1][j + 1] = Math.min(dp[i + 1][j + 1], dp[i][j]);
                    } else {
                        dp[i + 1][j + 1] = Math.min(dp[i + 1][j + 1], dp[i][j] + 1);
                    }
                }
            }
        }

        if (dp[n][m] <= M) {
            System.out.println("Yes");
        } else {
            System.out.println("No");
        }
    }
}

using namespace std;

long long solve(vector<long long> a, int k) {
    int n = a.size();
    int pos = k;
    long long jordan_size = a[k];

    while (true) {
        bool absorbed = false;


        if (pos > 0 && a[pos-1] < jordan_size) {
            jordan_size += a[pos-1];
            a.erase(a.begin() + pos - 1);
            pos--;
            absorbed = true;
        }

        else if (pos < a.size() - 1 && a[pos+1] < jordan_size) {
            jordan_size += a[pos+1];
            a.erase(a.begin() + pos + 1);
            absorbed = true;
        }

        if (!absorbed) break;
        a[pos] = jordan_size;
    }

    return jordan_size;
}

